// 1. Navigate
await page.goto('https://example.com/signup');

// 2. Snapshot to get element refs
// Claude sees: e12=textbox[email], e15=button[Continue]

// 3. Fill form using refs
await page.locator('e12').fill('user@example.com');
await page.locator('e14').fill('Password123!');

// 4. Click button
await page.locator('e15').click();

// 5. Wait for navigation
await page.waitForLoadState('networkidle');

// 6. Verify
await page.takeScreenshot();

// Claude can generate this from your plain-English request:
// "Sign up for the account with email test@example.com"

import { test, expect } from '@playwright/test';

test('signup flow', async ({ page }) => {
  await page.goto('https://example.com/signup');

  // Semantic locators discovered via accessibility tree
  await page.getByRole('textbox', { name: 'Email' }).fill('test@example.com');
  await page.getByRole('textbox', { name: 'Password' }).fill('SecurePass123');
  await page.getByRole('textbox', { name: 'Full Name' }).fill('John Doe');
  await page.getByRole('checkbox', { name: 'Terms' }).check();
  await page.getByRole('button', { name: 'Continue' }).click();

  // Wait for navigation
  await page.waitForLoadState('networkidle');

  // Verify success
  await expect(page.getByRole('heading')).toContainText('Dashboard');
});
